#ifdef __cplusplus
extern "C" {
#endif

#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>
#include <sys/time.h>

#define fp float

#define NUMBER_PAR_PER_BOX 100
#define NUMBER_THREADS 128

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct
{
	fp x, y, z;
} THREE_VECTOR;

typedef struct
{
	fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
	int x, y, z;
	int number;
	long offset;
} nei_str;

typedef struct box_str
{
	int x, y, z;
	int number;
	long offset;
	int nn;
	nei_str nei[26];
} box_str;

typedef struct par_str
{
	fp alpha;
} par_str;

typedef struct dim_str
{
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;
	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;
} dim_str;

void kernel_cpu(par_str d_par_gpu,
				dim_str d_dim_gpu,
				box_str *d_box_gpu,
				FOUR_VECTOR *d_rv_gpu,
				fp *d_qv_gpu,
				FOUR_VECTOR *d_fv_gpu)
{
	int number_boxes = (int)d_dim_gpu.number_boxes;

	#pragma omp parallel for schedule(static)
	for (int bx = 0; bx < number_boxes; bx++) {

		fp a2 = 2.0f * d_par_gpu.alpha * d_par_gpu.alpha;
		int first_i = d_box_gpu[bx].offset;

		FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
		FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
		fp qB_shared[NUMBER_PAR_PER_BOX];

		for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
			rA_shared[wtx] = d_rv_gpu[first_i + wtx];
		}

		for (int k = 0; k < (1 + d_box_gpu[bx].nn); k++) {
			int pointer;
			if (k == 0) {
				pointer = bx;
			} else {
				pointer = d_box_gpu[bx].nei[k-1].number;
			}

			int first_j = d_box_gpu[pointer].offset;

			for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				rB_shared[wtx] = d_rv_gpu[first_j + wtx];
				qB_shared[wtx] = d_qv_gpu[first_j + wtx];
			}

			for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
					fp r2 = rA_shared[wtx].v + rB_shared[j].v - DOT(rA_shared[wtx], rB_shared[j]);
					fp u2 = a2 * r2;
					fp vij = exp(-u2);
					fp fs = 2.0f * vij;

					THREE_VECTOR d;
					d.x = rA_shared[wtx].x - rB_shared[j].x;
					d.y = rA_shared[wtx].y - rB_shared[j].y;
					d.z = rA_shared[wtx].z - rB_shared[j].z;

					fp fxij = fs * d.x;
					fp fyij = fs * d.y;
					fp fzij = fs * d.z;

					d_fv_gpu[first_i + wtx].v += qB_shared[j] * vij;
					d_fv_gpu[first_i + wtx].x += qB_shared[j] * fxij;
					d_fv_gpu[first_i + wtx].y += qB_shared[j] * fyij;
					d_fv_gpu[first_i + wtx].z += qB_shared[j] * fzij;
				}
			}
		}
	}
}

void kernel_gpu_opencl_wrapper(par_str par_cpu,
								dim_str dim_cpu,
								box_str* box_cpu,
								FOUR_VECTOR* rv_cpu,
								fp* qv_cpu,
								FOUR_VECTOR* fv_cpu)
{
#ifdef TIMING
    struct timeval tv_total_start, tv_total_end, tv_init_end, tv_close_start, tv_close_end;
    struct timeval tv;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0, d2h_time = 0, close_time = 0, total_time = 0;

    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    mem_alloc_time = 0; 
    h2d_time = 0;
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    kernel_cpu(par_cpu, dim_cpu, box_cpu, rv_cpu, qv_cpu, fv_cpu);

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    kernel_time = close_time; 
    d2h_time = 0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    printf("Time spent in different stages of the application:\n");
    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}

#ifdef __cplusplus
}
#endif
